    // call API\n  }}\n/>\n```\n\n### Best practices\n- Use `onChange` alone for purely client-side filtering (no debounce needed)\n- Use `onDebouncedChange` (with `debounceMs` ≥ 300) for any network call\n- Initialize `value` from the URL so the search survives page refresh and sharing\n- Always handle the empty string `""` in your fetch — it typically means "no filter"\n        '}}},argTypes:{placeholder:{control:"text",description:"Placeholder shown when empty."},disabled:{control:"boolean",description:"Disables the input."},debounceMs:{control:"number",description:"Debounce delay in ms for `onDebouncedChange`."},value:{control:"text",description:"Controlled value (e.g. from URL param)."},onChange:{action:"onChange",description:"Fires on every keystroke."},onDebouncedChange:{action:"onDebouncedChange",description:"Fires after user stops typing."}}},Default={args:{placeholder:"Search..."}},Disabled={args:{placeholder:"Search unavailable",disabled:!0}},LocalFilter={name:"Local filter (onChange)",render:()=>{const[filter,setFilter]=(0,react__WEBPACK_IMPORTED_MODULE_1__.useState)(""),filtered=["Apple","Banana","Cherry","Date","Elderberry","Fig","Grape"].filter(i=>i.toLowerCase().includes(filter.toLowerCase()));return(0,react_jsx_runtime__WEBPACK_IMPORTED_MODULE_0__.jsxs)("div",{style:{display:"flex",flexDirection:"column",gap:"12px"},children:[(0,react_jsx_runtime__WEBPACK_IMPORTED_MODULE_0__.jsx)(_InputSearch__WEBPACK_IMPORTED_MODULE_2__.A,{placeholder:"Filter fruits...",onChange:setFilter}),(0,react_jsx_runtime__WEBPACK_IMPORTED_MODULE_0__.jsx)("ul",{style:{margin:0,paddingLeft:"16px"},children:filtered.length>0?filtered.map(item=>(0,react_jsx_runtime__WEBPACK_IMPORTED_MODULE_0__.jsx)("li",{children:item},item)):(0,react_jsx_runtime__WEBPACK_IMPORTED_MODULE_0__.jsx)("li",{style:{color:"gray"},children:"No results"})})]})},parameters:{docs:{description:{story:"Uses `onChange` for instant client-side filtering. No debounce needed since no network call is made."}}}},D